def validate(args, output):
    nums = args[0]
    if not isinstance(output, list):
        return False
    if len(output) != len(nums):
        return False
    if sorted(output) != sorted(nums):
        return False
    for i in range(1, len(output) - 1):
        if 2 * output[i] == output[i - 1] + output[i + 1]:
            return False
    return True

