class Solution:
    def rearrangeArray(self, nums):
        a = sorted(nums)
        n = len(a)
        half = (n + 1) // 2
        low = a[:half]
        high = a[half:]
        res = []
        for i in range(n):
            if i % 2 == 0:
                res.append(low[i // 2])
            else:
                res.append(high[i // 2])
        return res

