var rearrangeArray = function(nums) {
    const a = nums.slice().sort((x, y) => x - y);
    const n = a.length;
    const half = Math.floor((n + 1) / 2);
    const low = a.slice(0, half);
    const high = a.slice(half);
    const res = [];
    for (let i = 0; i < n; i++) {
        if (i % 2 === 0) res.push(low[i >> 1]);
        else res.push(high[i >> 1]);
    }
    return res;
};
